// openEHR FieldRenderer — recursive, rmType-aware form field renderer.
//
// Anchored in: docs/architecture.md §7 (form pipeline).
// rmType → shadcn component mapping per §7 table.
//
// CONTRACT: the form-state shape this renderer reads/writes MUST match exactly
// what `generateFormSchema(template)` validates AND what `formStateToFlat`
// consumes. Both are the authoritative source of truth. This renderer derives
// its structure from the WebTemplateNode tree — it never invents a new
// form-state shape.
//
// Validation comes from the Zod schema generated by generateFormSchema (via
// zodResolver in ComposeForm). No hand-written validation rules live here
// (Inviolable rule 1 for the form pipeline).

import { useEffect, useState } from 'react'
import {
  type Control,
  type FieldValues,
  Controller,
  type FieldError,
  useFieldArray,
  useFormContext,
} from 'react-hook-form'
import { useQuery } from '@tanstack/react-query'

import type { WebTemplateInput, WebTemplateNode } from '@ehrbase-ui/openehr-web-template'
import { m } from '@ehrbase-ui/i18n/messages'

import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Switch } from '@/components/ui/switch'
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover'
import {
  Command,
  CommandEmpty,
  CommandInput,
  CommandItem,
  CommandList,
} from '@/components/ui/command'
import { Calendar } from '@/components/ui/calendar'
import { Button } from '@/components/ui/button'
import { cn } from '@/lib/utils'
import { expandValueSet } from '@/server/functions/terminology.functions'

// ── Container rmTypes ─────────────────────────────────────────────────────────
// These nodes recurse into children; they are never leaf inputs themselves.
const CONTAINER_RM_TYPES = new Set([
  'COMPOSITION',
  'SECTION',
  'CLUSTER',
  'ITEM_TREE',
  'ITEM_LIST',
  'ITEM_SINGLE',
  'ITEM_TABLE',
  'HISTORY',
  'EVENT',
  'POINT_EVENT',
  'INTERVAL_EVENT',
  'EVENT_CONTEXT',
  'ADMIN_ENTRY',
  'OBSERVATION',
  'EVALUATION',
  'INSTRUCTION',
  'ACTION',
  'ELEMENT',
])

// Helper: resolve the localized display name for a node.
function nodeName(node: WebTemplateNode): string {
  return (
    node.localizedNames?.['en'] ??
    node.localizedName ??
    node.name ??
    node.id
  )
}

// Helper: does the node have no inputs AND is in the container set?
function isContainer(node: WebTemplateNode): boolean {
  const hasInputs = (node.inputs?.length ?? 0) > 0
  return !hasInputs && CONTAINER_RM_TYPES.has(node.rmType)
}

// Helper: max-length heuristic for DV_TEXT → Textarea vs Input.
// The §7 table says: textarea if maxLength > 80. We use the validation range
// max as a proxy; if unconstrained, default to Textarea (clinical notes).
function isLongText(node: WebTemplateNode): boolean {
  const inp = node.inputs?.[0]
  const maxLen = inp?.validation?.range?.max
  if (typeof maxLen === 'number') return maxLen > 80
  return true
}

// Helper: extract an error message from an RHF FieldError.
function errorMessage(error: FieldError | undefined): string | undefined {
  if (!error) return undefined
  return error.message ?? 'Invalid value'
}

// ── External terminology binding (F2 — ADR-0034) ──────────────────────────────
// A DV_CODED_TEXT input's `terminology` is the binding source. `local` (the
// template's own value-list) and `openehr` (the internal openEHR codesets) are
// CLOSED, in-template lists → render the static Select. Anything else is an
// EXTERNAL binding (SNOMED CT / LOINC / national codes) with no fixed in-template
// option list → render the live combobox backed by the terminology server.
const LOCAL_TERMINOLOGIES = new Set(['local', 'openehr'])

// Map the web-template terminology name to a FHIR CodeSystem URL so $expand has
// a `system` to expand when the template doesn't carry a ValueSet URL. Unknown
// names pass through verbatim (a server may accept the bare name as its system).
const TERMINOLOGY_SYSTEM_URI: Record<string, string> = {
  'SNOMED-CT': 'http://snomed.info/sct',
  'SNOMED CT': 'http://snomed.info/sct',
  SNOMED: 'http://snomed.info/sct',
  LOINC: 'http://loinc.org',
  'ICD-10': 'http://hl7.org/fhir/sid/icd-10',
  'ICD10': 'http://hl7.org/fhir/sid/icd-10',
  ATC: 'http://www.whocc.no/atc',
}

interface ExternalBinding {
  /** The terminology name as written in the template (for the picker label). */
  terminology: string
  /** A ValueSet canonical URL, when the template carries one. */
  valueSetUrl?: string
  /** The CodeSystem URL to expand when no ValueSet URL is bound. */
  system?: string
}

// Decide static-Select vs live-combobox for a DV_CODED_TEXT code input.
// Returns the external binding when the field should use the live combobox, else
// null (→ keep the existing static Select / datalist behaviour, no F1 regression).
function externalBindingOf(codeInput: WebTemplateInput | undefined): ExternalBinding | null {
  if (!codeInput) return null
  const term = codeInput.terminology
  if (!term || LOCAL_TERMINOLOGIES.has(term)) return null
  // A closed in-template list wins even for an external terminology name: the
  // template author fixed the options, so honour them (static Select).
  const hasClosedList = (codeInput.list?.length ?? 0) > 0 && !codeInput.listOpen
  if (hasClosedList) return null
  // A bound ValueSet URL (some templates carry one in `terminology` as a URL, or
  // via a constraint) is preferred; otherwise expand the whole code system.
  const isUrl = term.startsWith('http://') || term.startsWith('https://')
  const system = TERMINOLOGY_SYSTEM_URI[term] ?? (isUrl ? undefined : term)
  return {
    terminology: term,
    valueSetUrl: isUrl ? term : undefined,
    system,
  }
}

// Debounce a changing value (the autocomplete query) so each keystroke does not
// fire a server round trip. 250ms is the common autocomplete debounce.
function useDebouncedValue<T>(value: T, delayMs: number): T {
  const [debounced, setDebounced] = useState(value)
  useEffect(() => {
    const handle = setTimeout(() => setDebounced(value), delayMs)
    return () => clearTimeout(handle)
  }, [value, delayMs])
  return debounced
}

// Helper: type guard for composite form-state leaf records (DV_QUANTITY etc.).
function isCompositeRecord(x: unknown): x is Record<string, unknown> {
  return typeof x === 'object' && x !== null && !Array.isArray(x)
}

// ── Required marker ───────────────────────────────────────────────────────────
function RequiredMark() {
  return (
    <span className="text-destructive ml-1" aria-label={m.compose_required_label()}>
      {m.compose_required_marker()}
    </span>
  )
}

// ── Read-only static value display ───────────────────────────────────────────
// When readOnly=true, leaf values are rendered as labelled static text instead
// of interactive inputs. This is the display mode used by CompositionViewer.

interface ReadOnlyLeafProps {
  label: string
  value: string
}

function ReadOnlyField({ label, value }: ReadOnlyLeafProps) {
  return (
    <div className="flex flex-col gap-0.5">
      <span className="text-muted-foreground text-xs font-medium">{label}</span>
      <span className="text-sm">{value || m.compose_value_empty()}</span>
    </div>
  )
}

// ── Leaf renderers ────────────────────────────────────────────────────────────

interface LeafProps {
  node: WebTemplateNode
  path: string
  control: Control<Record<string, unknown>>
  readOnly?: boolean
}

// DV_TEXT → Input (short) / Textarea (long). §7 table row 1.
function DvTextField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const long = isLongText(node)
  const label = nodeName(node)
  const inputId = `field-${path}`

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const val = typeof field.value === 'string' ? field.value : ''
        const err = errorMessage(fieldState.error)
        if (readOnly) return <ReadOnlyField label={label} value={val} />
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={inputId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            {long ? (
              <Textarea
                id={inputId}
                value={val}
                onChange={(e) => field.onChange(e.target.value)}
                onBlur={field.onBlur}
                aria-invalid={fieldState.invalid}
                aria-describedby={err ? `${inputId}-err` : undefined}
              />
            ) : (
              <Input
                id={inputId}
                type="text"
                value={val}
                onChange={(e) => field.onChange(e.target.value)}
                onBlur={field.onBlur}
                aria-invalid={fieldState.invalid}
                aria-describedby={err ? `${inputId}-err` : undefined}
              />
            )}
            {err && (
              <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// ── DV_CODED_TEXT external-binding combobox (F2 — ADR-0034) ───────────────────
// A live, debounced terminology picker (Popover + Command) for a code input
// bound to an external terminology. Writes the FULL composite form-state object
// `{ code, value, terminology }` at `path` so the FLAT converter emits `|code`,
// `|value`, and `|terminology` (the closed-list Select path writes only `|code`;
// the external path must carry display + terminology too).
//
// Form-state shape: `{ code: string, value: string, terminology: string }` —
// matches dvCodedTextSchema() in generate-form-schema.ts (the optional
// `terminology` companion key).

interface TermComboboxProps extends LeafProps {
  binding: ExternalBinding
}

function isTermSelection(x: unknown): x is { code?: unknown; value?: unknown } {
  return typeof x === 'object' && x !== null && !Array.isArray(x)
}

function TermComboboxField({ node, path, control, binding, readOnly }: TermComboboxProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const triggerId = `field-${path}.code`
  const [open, setOpen] = useState(false)
  const [query, setQuery] = useState('')
  const debouncedQuery = useDebouncedValue(query, 250)

  // Query the terminology server on the debounced filter. Disabled until the
  // popover is open so a hidden field never fires a request.
  const expansion = useQuery({
    queryKey: [
      'terminology',
      'expand',
      binding.valueSetUrl ?? null,
      binding.system ?? null,
      debouncedQuery,
    ],
    queryFn: () =>
      expandValueSet({
        data: {
          url: binding.valueSetUrl,
          system: binding.system,
          filter: debouncedQuery.length > 0 ? debouncedQuery : undefined,
          count: 20,
          offset: 0,
        },
      }),
    enabled: open,
    staleTime: 60_000,
  })

  const notConfigured = expansion.data?.configured === false
  const options = expansion.data?.options ?? []

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const selection = isTermSelection(field.value) ? field.value : undefined
        const selectedCode = typeof selection?.code === 'string' ? selection.code : ''
        const selectedDisplay = typeof selection?.value === 'string' ? selection.value : ''
        const err = errorMessage(fieldState.error)

        if (readOnly) {
          return <ReadOnlyField label={label} value={selectedDisplay || selectedCode} />
        }

        const buttonLabel = selectedDisplay
          ? m.compose_term_selected({ display: selectedDisplay })
          : m.compose_term_search_select()

        const onSelectOption = (code: string, display: string) => {
          field.onChange({ code, value: display, terminology: binding.terminology })
          setOpen(false)
          setQuery('')
        }

        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={triggerId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <div aria-describedby={err ? `${triggerId}-err` : undefined}>
              <Popover open={open} onOpenChange={setOpen}>
                <PopoverTrigger asChild>
                  {/* aria-invalid is conveyed by the wrapping div's
                      aria-describedby + the destructive border; buttons don't
                      support aria-invalid (role-supports-aria-props). */}
                  <Button
                    id={triggerId}
                    type="button"
                    variant="outline"
                    className={cn(
                      'w-full justify-start text-left font-normal',
                      !selectedDisplay && 'text-muted-foreground',
                      fieldState.invalid && 'border-destructive',
                    )}
                  >
                    {buttonLabel}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-[--radix-popover-trigger-width] p-0" align="start">
                  {/* shouldFilter={false}: results are server-filtered, not client-filtered. */}
                  <Command shouldFilter={false}>
                    <CommandInput
                      value={query}
                      onValueChange={setQuery}
                      placeholder={m.compose_term_search_placeholder({ terminology: binding.terminology })}
                    />
                    <CommandList>
                      {notConfigured ? (
                        <CommandEmpty>{m.compose_term_not_configured()}</CommandEmpty>
                      ) : expansion.isError ? (
                        <CommandEmpty>{m.compose_term_error()}</CommandEmpty>
                      ) : expansion.isFetching ? (
                        <CommandEmpty>{m.compose_term_searching()}</CommandEmpty>
                      ) : options.length === 0 ? (
                        <CommandEmpty>
                          {debouncedQuery.length > 0
                            ? m.compose_term_no_results()
                            : m.compose_term_type_to_search()}
                        </CommandEmpty>
                      ) : (
                        options.map((opt) => (
                          <CommandItem
                            key={`${opt.system}|${opt.code}`}
                            value={opt.code}
                            onSelect={() => onSelectOption(opt.code, opt.display)}
                          >
                            {opt.display}
                          </CommandItem>
                        ))
                      )}
                    </CommandList>
                  </Command>
                </PopoverContent>
              </Popover>
            </div>
            {selectedCode && (
              <p className="text-muted-foreground text-xs">
                {binding.terminology}: {selectedCode}
              </p>
            )}
            {err && (
              <p id={`${triggerId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_CODED_TEXT → Select (≤7 options) / Combobox (>7 or open list). §7 table row 2.
// Form-state shape: `{ code: string }` when a code suffix exists; scalar string
// for single suffix-less input — matching leafSchema() in generate-form-schema.ts.
function DvCodedTextField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputs = node.inputs ?? []
  const codeInput = inputs.find((i) => i.suffix === 'code') ?? inputs[0]
  const list = codeInput?.list ?? []
  const isClosedList = list.length > 0 && !codeInput?.listOpen
  const isSmall = isClosedList && list.length <= 7
  const hasCodeSuffix = !!inputs.find((i) => i.suffix === 'code')
  const fieldPath = hasCodeSuffix ? `${path}.code` : path
  const inputId = `field-${fieldPath}`

  // EXTERNAL binding (F2 — ADR-0034): a code input bound to an external
  // terminology (SNOMED CT / LOINC / national codes) with no closed in-template
  // list → live combobox backed by the terminology server. Closed local/openEHR
  // lists keep the static Select below (no F1 regression).
  const externalBinding = externalBindingOf(codeInput)
  if (externalBinding && hasCodeSuffix) {
    return (
      <TermComboboxField
        node={node}
        path={path}
        control={control}
        binding={externalBinding}
        readOnly={readOnly}
      />
    )
  }

  return (
    <Controller
      control={control}
      name={fieldPath}
      render={({ field, fieldState }) => {
        const val = typeof field.value === 'string' ? field.value : ''
        const err = errorMessage(fieldState.error)

        if (readOnly) {
          // Resolve the display label for the current code value.
          const displayLabel = list.find((i) => i.value === val)
            ?.localizedLabels?.['en'] ?? list.find((i) => i.value === val)?.label ?? val
          return <ReadOnlyField label={label} value={displayLabel} />
        }

        if (isSmall) {
          return (
            <div className="flex flex-col gap-1">
              <Label htmlFor={inputId}>
                {label}
                {required && <RequiredMark />}
              </Label>
              <Select value={val} onValueChange={(v) => field.onChange(v)}>
                <SelectTrigger id={inputId} aria-invalid={fieldState.invalid}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {list.map((item) => (
                    <SelectItem key={item.value} value={item.value}>
                      {item.localizedLabels?.['en'] ?? item.label ?? item.value}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {err && (
                <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                  {err}
                </p>
              )}
            </div>
          )
        }

        // Large or open list: Input with datalist (combobox pattern).
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={inputId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <Input
              id={inputId}
              type="text"
              value={val}
              onChange={(e) => field.onChange(e.target.value)}
              onBlur={field.onBlur}
              aria-invalid={fieldState.invalid}
              aria-describedby={err ? `${inputId}-err` : undefined}
              list={list.length > 0 ? `${inputId}-list` : undefined}
            />
            {list.length > 0 && (
              <datalist id={`${inputId}-list`}>
                {list.map((item) => (
                  <option key={item.value} value={item.value}>
                    {item.localizedLabels?.['en'] ?? item.label ?? item.value}
                  </option>
                ))}
              </datalist>
            )}
            {err && (
              <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_QUANTITY → number Input + unit Select. §7 table row 3.
// Form-state shape: `{ magnitude: number, unit: string }` (composite leaf).
function DvQuantityField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputs = node.inputs ?? []
  const magnitudeInput = inputs.find((i) => i.suffix === 'magnitude')
  const unitInput = inputs.find((i) => i.suffix === 'unit')
  const units = unitInput?.list ?? []
  const magId = `field-${path}.magnitude`
  const unitId = `field-${path}.unit`

  if (readOnly) {
    return (
      <Controller
        control={control}
        name={path}
        render={({ field }) => {
          const composite = field.value
          const raw = isCompositeRecord(composite) ? composite : {}
          const mag = typeof raw['magnitude'] === 'number' ? raw['magnitude'] : undefined
          const unit = typeof raw['unit'] === 'string' ? raw['unit'] : undefined
          const display = [mag !== undefined ? String(mag) : '', unit ?? '']
            .filter(Boolean)
            .join(' ')
          return <ReadOnlyField label={label} value={display} />
        }}
      />
    )
  }

  return (
    <fieldset className="flex flex-col gap-1">
      <legend className="text-sm font-medium leading-none">
        {label}
        {required && <RequiredMark />}
      </legend>
      <div className="flex gap-2">
        <Controller
          control={control}
          name={`${path}.magnitude`}
          render={({ field, fieldState }) => {
            const numVal = typeof field.value === 'number' ? field.value : ''
            const err = errorMessage(fieldState.error)
            const rangeMin = magnitudeInput?.validation?.range?.min
            const rangeMax = magnitudeInput?.validation?.range?.max
            return (
              <div className="flex flex-1 flex-col gap-1">
                <Label htmlFor={magId} className="sr-only">
                  {label} magnitude
                </Label>
                <Input
                  id={magId}
                  type="number"
                  value={numVal}
                  min={typeof rangeMin === 'number' ? rangeMin : undefined}
                  max={typeof rangeMax === 'number' ? rangeMax : undefined}
                  step="any"
                  onChange={(e) => {
                    const v = e.target.value
                    field.onChange(v === '' ? undefined : Number(v))
                  }}
                  onBlur={field.onBlur}
                  aria-invalid={fieldState.invalid}
                  aria-describedby={err ? `${magId}-err` : undefined}
                />
                {err && (
                  <p id={`${magId}-err`} role="alert" className="text-destructive text-xs">
                    {err}
                  </p>
                )}
              </div>
            )
          }}
        />
        {units.length > 0 && (
          <Controller
            control={control}
            name={`${path}.unit`}
            render={({ field, fieldState }) => {
              const val = typeof field.value === 'string' ? field.value : ''
              return (
                <div className="flex flex-col gap-1">
                  <Label htmlFor={unitId} className="sr-only">
                    {label} unit
                  </Label>
                  <Select value={val} onValueChange={(v) => field.onChange(v)}>
                    <SelectTrigger id={unitId} aria-invalid={fieldState.invalid}>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {units.map((u) => (
                        <SelectItem key={u.value} value={u.value}>
                          {u.localizedLabels?.['en'] ?? u.label ?? u.value}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )
            }}
          />
        )}
      </div>
    </fieldset>
  )
}

// DV_COUNT → number Input (integer step). §7 table row 4.
// Form-state shape: scalar number (single suffix-less INTEGER input).
function DvCountField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputId = `field-${path}`
  const inp = node.inputs?.[0]
  const rangeMin = inp?.validation?.range?.min
  const rangeMax = inp?.validation?.range?.max

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const numVal = typeof field.value === 'number' ? field.value : ''
        const err = errorMessage(fieldState.error)
        if (readOnly) return <ReadOnlyField label={label} value={numVal !== '' ? String(numVal) : ''} />
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={inputId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <Input
              id={inputId}
              type="number"
              step="1"
              value={numVal}
              min={typeof rangeMin === 'number' ? rangeMin : undefined}
              max={typeof rangeMax === 'number' ? rangeMax : undefined}
              onChange={(e) => {
                const v = e.target.value
                field.onChange(v === '' ? undefined : Number(v))
              }}
              onBlur={field.onBlur}
              aria-invalid={fieldState.invalid}
              aria-describedby={err ? `${inputId}-err` : undefined}
            />
            {err && (
              <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_BOOLEAN → Switch with inline label. §7 table row 5.
// Form-state shape: scalar boolean.
function DvBooleanField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const switchId = `field-${path}`

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const checked = field.value === true
        const err = errorMessage(fieldState.error)
        if (readOnly) return <ReadOnlyField label={label} value={checked ? 'Yes' : 'No'} />
        return (
          <div className="flex flex-col gap-1">
            <div className="flex items-center gap-2">
              <Switch
                id={switchId}
                checked={checked}
                onCheckedChange={(v) => field.onChange(v)}
                aria-invalid={fieldState.invalid}
              />
              <Label htmlFor={switchId}>
                {label}
                {required && <RequiredMark />}
              </Label>
            </div>
            {err && (
              <p role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_DATE → Calendar + Popover. §7 table row 6.
// Form-state shape: ISO 8601 date string (bare FLAT key, no |suffix).
// useState is in the component body (not inside the render callback) per the Rules of Hooks.
function DvDateField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const triggerId = `field-${path}`
  // Popover open state lives in the component body, not inside the render callback.
  const [open, setOpen] = useState(false)

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const strVal = typeof field.value === 'string' ? field.value : ''
        const dateVal = strVal ? new Date(strVal) : undefined
        const err = errorMessage(fieldState.error)

        if (readOnly) return <ReadOnlyField label={label} value={strVal} />

        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={triggerId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            {/* aria-describedby on the trigger div conveys the invalid state.
                Buttons don't support aria-invalid (role-supports-aria-props). */}
            <div
              aria-describedby={err ? `${triggerId}-err` : undefined}
            >
              <Popover open={open} onOpenChange={setOpen}>
                <PopoverTrigger asChild>
                  <Button
                    id={triggerId}
                    variant="outline"
                    type="button"
                    className={cn(
                      'w-full justify-start text-left font-normal',
                      !strVal && 'text-muted-foreground',
                      fieldState.invalid && 'border-destructive',
                    )}
                  >
                    {strVal || label}
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0" align="start">
                  <Calendar
                    mode="single"
                    selected={dateVal}
                    onSelect={(d) => {
                      if (d) {
                        field.onChange(d.toISOString().slice(0, 10))
                      }
                      setOpen(false)
                    }}
                  />
                </PopoverContent>
              </Popover>
            </div>
            {err && (
              <p id={`${triggerId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_DATE_TIME → datetime-local Input. §7 table row 6 (full datetime).
// Form-state shape: ISO 8601 datetime string (bare FLAT key, no |suffix).
function DvDateTimeField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputId = `field-${path}`

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const strVal = typeof field.value === 'string' ? field.value : ''
        const err = errorMessage(fieldState.error)
        const localVal = strVal ? strVal.slice(0, 16) : ''
        if (readOnly) return <ReadOnlyField label={label} value={strVal} />
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={inputId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <Input
              id={inputId}
              type="datetime-local"
              value={localVal}
              onChange={(e) => {
                field.onChange(e.target.value ? `${e.target.value}:00` : '')
              }}
              onBlur={field.onBlur}
              aria-invalid={fieldState.invalid}
              aria-describedby={err ? `${inputId}-err` : undefined}
            />
            {err && (
              <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

