// DV_ORDINAL → RadioGroup (≤7 options) / Select (>7). §7 table row 7.
// Form-state shape: mirrors DV_CODED_TEXT (code suffix → `{ code }`, else scalar).
function DvOrdinalField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputs = node.inputs ?? []
  const codeInput = inputs.find((i) => i.suffix === 'code') ?? inputs[0]
  const list = codeInput?.list ?? []
  const isSmall = list.length <= 7
  const hasCodeSuffix = !!inputs.find((i) => i.suffix === 'code')
  const fieldPath = hasCodeSuffix ? `${path}.code` : path
  const groupId = `field-${fieldPath}`

  return (
    <Controller
      control={control}
      name={fieldPath}
      render={({ field, fieldState }) => {
        const val = typeof field.value === 'string' ? field.value : ''
        const err = errorMessage(fieldState.error)

        if (readOnly) {
          const displayLabel = list.find((i) => i.value === val)?.localizedLabels?.['en']
            ?? list.find((i) => i.value === val)?.label ?? val
          return <ReadOnlyField label={label} value={displayLabel} />
        }

        if (isSmall) {
          return (
            <fieldset className="flex flex-col gap-2">
              <legend className="text-sm font-medium leading-none">
                {label}
                {required && <RequiredMark />}
              </legend>
              <RadioGroup
                id={groupId}
                value={val}
                onValueChange={(v) => field.onChange(v)}
                aria-invalid={fieldState.invalid}
              >
                {list.map((item, idx) => {
                  const radioId = `${groupId}-${idx}`
                  const itemLabel =
                    item.localizedLabels?.['en'] ?? item.label ?? item.value
                  const ordinalDisplay =
                    typeof item.ordinal === 'number' ? `${item.ordinal}. ` : ''
                  return (
                    <div key={item.value} className="flex items-center gap-2">
                      <RadioGroupItem id={radioId} value={item.value} />
                      <Label htmlFor={radioId}>
                        {ordinalDisplay}
                        {itemLabel}
                      </Label>
                    </div>
                  )
                })}
              </RadioGroup>
              {err && (
                <p role="alert" className="text-destructive text-xs">
                  {err}
                </p>
              )}
            </fieldset>
          )
        }

        const selectId = `field-${fieldPath}-select`
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={selectId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <Select value={val} onValueChange={(v) => field.onChange(v)}>
              <SelectTrigger id={selectId} aria-invalid={fieldState.invalid}>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {list.map((item) => (
                  <SelectItem key={item.value} value={item.value}>
                    {typeof item.ordinal === 'number' ? `${item.ordinal}. ` : ''}
                    {item.localizedLabels?.['en'] ?? item.label ?? item.value}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            {err && (
              <p role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// DV_PROPORTION → two number Inputs + slash. §7 table row 8.
// Form-state shape: `{ numerator: number, denominator: number }`.
function DvProportionField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const numId = `field-${path}.numerator`
  const denomId = `field-${path}.denominator`

  if (readOnly) {
    return (
      <Controller
        control={control}
        name={path}
        render={({ field }) => {
          const composite = field.value
          const raw = isCompositeRecord(composite) ? composite : {}
          const num = typeof raw['numerator'] === 'number' ? raw['numerator'] : undefined
          const denom = typeof raw['denominator'] === 'number' ? raw['denominator'] : undefined
          const display = [num !== undefined ? String(num) : '', denom !== undefined ? String(denom) : '']
            .filter(Boolean)
            .join(' / ')
          return <ReadOnlyField label={label} value={display} />
        }}
      />
    )
  }

  return (
    <fieldset className="flex flex-col gap-1">
      <legend className="text-sm font-medium leading-none">
        {label}
        {required && <RequiredMark />}
      </legend>
      <div className="flex items-center gap-2">
        <Controller
          control={control}
          name={`${path}.numerator`}
          render={({ field, fieldState }) => (
            <div className="flex flex-col gap-1">
              <Label htmlFor={numId} className="sr-only">
                Numerator
              </Label>
              <Input
                id={numId}
                type="number"
                step="any"
                value={typeof field.value === 'number' ? field.value : ''}
                onChange={(e) => {
                  field.onChange(e.target.value === '' ? undefined : Number(e.target.value))
                }}
                onBlur={field.onBlur}
                aria-invalid={fieldState.invalid}
                className="w-24"
              />
            </div>
          )}
        />
        <span aria-hidden="true" className="text-muted-foreground">
          /
        </span>
        <Controller
          control={control}
          name={`${path}.denominator`}
          render={({ field, fieldState }) => (
            <div className="flex flex-col gap-1">
              <Label htmlFor={denomId} className="sr-only">
                Denominator
              </Label>
              <Input
                id={denomId}
                type="number"
                step="any"
                value={typeof field.value === 'number' ? field.value : ''}
                onChange={(e) => {
                  field.onChange(e.target.value === '' ? undefined : Number(e.target.value))
                }}
                onBlur={field.onBlur}
                aria-invalid={fieldState.invalid}
                className="w-24"
              />
            </div>
          )}
        />
      </div>
    </fieldset>
  )
}

