// DV_IDENTIFIER → composite text Inputs for id, type, issuer, assigner. §7 §7.x.
// Form-state shape: `{ id, type, issuer, assigner }` (composite object matching
// the four suffix inputs the template exposes). FLAT: |id, |type, |issuer, |assigner.
function DvIdentifierField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)

  if (readOnly) {
    return (
      <Controller
        control={control}
        name={path}
        render={({ field }) => {
          const composite = isCompositeRecord(field.value) ? field.value : {}
          const idVal = typeof composite['id'] === 'string' ? composite['id'] : ''
          return <ReadOnlyField label={label} value={idVal} />
        }}
      />
    )
  }

  const subFields: Array<{ suffix: string; labelText: string }> = [
    { suffix: 'id', labelText: 'ID' },
    { suffix: 'type', labelText: 'Type' },
    { suffix: 'issuer', labelText: 'Issuer' },
    { suffix: 'assigner', labelText: 'Assigner' },
  ]

  return (
    <fieldset className="flex flex-col gap-1">
      <legend className="text-sm font-medium leading-none">
        {label}
        {required && <RequiredMark />}
      </legend>
      <div className="grid grid-cols-2 gap-2">
        {subFields.map(({ suffix, labelText }) => {
          const subPath = `${path}.${suffix}`
          const subId = `field-${subPath}`
          return (
            <Controller
              key={suffix}
              control={control}
              name={subPath}
              render={({ field, fieldState }) => {
                const strVal = typeof field.value === 'string' ? field.value : ''
                const err = errorMessage(fieldState.error)
                return (
                  <div className="flex flex-col gap-1">
                    <Label htmlFor={subId} className="text-xs text-muted-foreground">
                      {labelText}
                    </Label>
                    <Input
                      id={subId}
                      type="text"
                      value={strVal}
                      onChange={(e) => field.onChange(e.target.value)}
                      onBlur={field.onBlur}
                      aria-invalid={fieldState.invalid}
                      aria-describedby={err ? `${subId}-err` : undefined}
                    />
                    {err && (
                      <p id={`${subId}-err`} role="alert" className="text-destructive text-xs">
                        {err}
                      </p>
                    )}
                  </div>
                )
              }}
            />
          )
        })}
      </div>
    </fieldset>
  )
}

// DV_MULTIMEDIA → file input stub. §7 table row 9.
// Full MIME sniffing / ClamAV / EXIF stripping is server-side (§7.x).
// This yields a descriptor object; the server fn handles the actual upload.
function DvMultimediaField({ node, path, control, readOnly }: LeafProps) {
  const required = (node.min ?? 0) >= 1
  const label = nodeName(node)
  const inputId = `field-${path}`

  return (
    <Controller
      control={control}
      name={path}
      render={({ field, fieldState }) => {
        const err = errorMessage(fieldState.error)
        if (readOnly) {
          const descriptor = isCompositeRecord(field.value) ? field.value : undefined
          const display = typeof descriptor?.['name'] === 'string' ? descriptor['name'] : ''
          return <ReadOnlyField label={label} value={display} />
        }
        return (
          <div className="flex flex-col gap-1">
            <Label htmlFor={inputId}>
              {label}
              {required && <RequiredMark />}
            </Label>
            <Input
              id={inputId}
              type="file"
              onChange={(e) => {
                const f = e.target.files?.[0]
                if (f) {
                  field.onChange({ name: f.name, size: f.size, type: f.type })
                }
              }}
              aria-invalid={fieldState.invalid}
              aria-describedby={err ? `${inputId}-err` : undefined}
            />
            <p className="text-muted-foreground text-xs">{m.compose_multimedia_hint()}</p>
            {err && (
              <p id={`${inputId}-err`} role="alert" className="text-destructive text-xs">
                {err}
              </p>
            )}
          </div>
        )
      }}
    />
  )
}

// Fallback for unmapped rmTypes. Renders a DISABLED placeholder so a clinician
// can see the field but cannot enter data that would be silently mis-encoded.
// Per the §7 rule: do NOT silently invent a mapping for a new rmType — open an
// ADR proposing the mapping, citing the openEHR RM entry.
function UnknownLeafField({ node }: Omit<LeafProps, 'path' | 'control'>) {
  const label = nodeName(node)
  const inputId = `field-unsupported-${node.id}`
  const placeholder = m.compose_unsupported_type({ rmType: node.rmType })
  return (
    <div className="flex flex-col gap-1">
      <Label htmlFor={inputId} className="text-muted-foreground">
        {label}
      </Label>
      <Input
        id={inputId}
        type="text"
        disabled
        placeholder={placeholder}
        aria-label={placeholder}
      />
    </div>
  )
}

// ── Leaf dispatcher ───────────────────────────────────────────────────────────

function renderLeaf(
  node: WebTemplateNode,
  path: string,
  control: Control<Record<string, unknown>>,
  readOnly?: boolean,
) {
  switch (node.rmType) {
    case 'DV_TEXT':
      return <DvTextField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_CODED_TEXT':
      return <DvCodedTextField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_QUANTITY':
      return <DvQuantityField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_COUNT':
      return <DvCountField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_BOOLEAN':
      return <DvBooleanField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_DATE':
      return <DvDateField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_DATE_TIME':
      return <DvDateTimeField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_TIME':
      return <DvTimeField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_ORDINAL':
      return <DvOrdinalField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_PROPORTION':
      return <DvProportionField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_DURATION':
      return <DvDurationField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_IDENTIFIER':
      return <DvIdentifierField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_MULTIMEDIA':
      return <DvMultimediaField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    case 'DV_URI':
    case 'DV_EHR_URI':
      // URI renders as plain text; form-state shape is scalar string.
      return <DvTextField key={path} node={node} path={path} control={control} readOnly={readOnly} />
    default:
      return <UnknownLeafField key={path} node={node} />
  }
}

// ── ArrayFieldRenderer (inline, no circular import) ──────────────────────────
// Handles multiply-occurring nodes (max > 1 or max === -1) with useFieldArray.
// ArrayFieldRenderer calls FieldRenderer with max overridden to 1 to prevent
// infinite recursion; the outer FieldRenderer routes to this when isMulti.

interface ArrayRendererInternalProps {
  node: WebTemplateNode
  path: string
  control: Control<Record<string, unknown>>
  depth: number
  readOnly?: boolean
}

// FieldValues-typed form context used ONLY inside ArrayRendererInternal so
// that useFieldArray sees the correct type (FieldValues = Record<string, unknown>
// is structurally compatible with its `name` constraint). This is a type
// annotation on the context extraction, not a cast.
function ArrayRendererInternal({
  node,
  path,
  control,
  depth,
  readOnly,
}: ArrayRendererInternalProps) {
  // useFormContext<FieldValues> avoids the useFieldArray name-type issue:
  // FieldValues = Record<string, any>, which useFieldArray's FieldArrayPath
  // resolves to string (all keys valid).
  const formCtx = useFormContext<FieldValues>()
  const { fields, append, remove } = useFieldArray({
    control: formCtx.control,
    name: path,
  })
  // Silence the unused `control` prop lint warning — it is kept in the interface
  // for API consistency with FieldRenderer.
  void control

  const label = nodeName(node)
  const min = node.min ?? 0
  const max = node.max ?? -1
  const isUnbounded = max === -1
  const atMax = !isUnbounded && fields.length >= max
  const atMin = fields.length <= min

  const hasInputs = (node.inputs?.length ?? 0) > 0
  const newItem = hasInputs ? undefined : {}

  return (
    <Card className={cn(depth === 0 && 'border-0 shadow-none p-0')}>
      {label && (
        <CardHeader className={cn(depth === 0 && 'px-0')}>
          <CardTitle className="text-base">{label}</CardTitle>
        </CardHeader>
      )}
      <CardContent className={cn('space-y-4', depth === 0 && 'px-0')}>
        {fields.length === 0 && (
          <p className="text-muted-foreground text-sm">{m.compose_array_add()}</p>
        )}

        {fields.map((fieldItem, index) => (
          <div key={fieldItem.id} className="relative rounded-md border p-3">
            <FieldRenderer
              node={{ ...node, max: 1 }}
              path={`${path}.${index}`}
              control={control}
              depth={depth + 1}
              readOnly={readOnly}
            />
            {!readOnly && (
              <div className="mt-2 flex justify-end">
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  disabled={atMin}
                  onClick={() => remove(index)}
                  aria-label={m.compose_array_remove({ index: String(index + 1) })}
                >
                  {m.compose_field_remove()}
                </Button>
              </div>
            )}
          </div>
        ))}

        {!readOnly && (
          <Button
            type="button"
            variant="secondary"
            size="sm"
            disabled={atMax}
            onClick={() => append(newItem)}
            aria-label={m.compose_array_add()}
          >
            {m.compose_field_add()}
          </Button>
        )}
      </CardContent>
    </Card>
  )
}

// ── FieldRenderer (exported) ─────────────────────────────────────────────────

export interface FieldRendererProps {
  node: WebTemplateNode
  /** Dot-notation path into the RHF form state. */
  path: string
  control: Control<Record<string, unknown>>
  /** Nesting depth; root = 0. Used for Card styling. */
  depth?: number
  /**
   * When true, all leaf inputs are rendered as static read-only text and
   * Add/Remove buttons are hidden. Used by CompositionViewer (§7 form pipeline).
   */
  readOnly?: boolean
}

/**
 * Recursive, rmType-aware field renderer for openEHR web templates.
 *
 * Routing logic:
 * - If max > 1 or max === -1 → ArrayRendererInternal (useFieldArray).
 * - If CONTAINER_RM_TYPES and no inputs → grouped Card/fieldset with children.
 * - Otherwise → leaf renderer dispatched by rmType.
 *
 * The form-state shape produced matches exactly what generateFormSchema builds
 * and what formStateToFlat consumes. Do not break this contract.
 *
 * When readOnly=true, leaf values render as static text; array Add/Remove
 * controls are hidden.  This mode is used by CompositionViewer.
 */
export function FieldRenderer({
  node,
  path,
  control,
  depth = 0,
  readOnly,
}: FieldRendererProps) {
  // Consume the form context to ensure RHF state is active.
  useFormContext()

  const isMulti = node.max === -1 || (node.max ?? 1) > 1
  if (isMulti) {
    return (
      <ArrayRendererInternal
        node={node}
        path={path}
        control={control}
        depth={depth}
        readOnly={readOnly}
      />
    )
  }

  if (isContainer(node)) {
    const label = nodeName(node)
    return (
      <Card className={cn(depth === 0 && 'border-0 shadow-none p-0')}>
        {label && (
          <CardHeader className={cn(depth === 0 && 'px-0')}>
            <CardTitle className="text-base">{label}</CardTitle>
          </CardHeader>
        )}
        <CardContent className={cn('space-y-4', depth === 0 && 'px-0')}>
          {(node.children ?? []).map((child) => {
            const childPath = path ? `${path}.${child.id}` : child.id
            return (
              <FieldRenderer
                key={child.id}
                node={child}
                path={childPath}
                control={control}
                depth={depth + 1}
                readOnly={readOnly}
              />
            )
          })}
        </CardContent>
      </Card>
    )
  }

  return renderLeaf(node, path, control, readOnly)
}
